{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for sensor timeout: no valid sensor frame for more than 1000 ms */
    bool is_timeout = false;
    if (controller->has_valid_sensor && input.now_ms > controller->last_valid_sensor_ms) {
        uint32_t elapsed = input.now_ms - controller->last_valid_sensor_ms;
        /* Handle wrap-around of 32-bit tick counter */
        if (elapsed > CONTROLLER_SENSOR_TIMEOUT_MS) {
            is_timeout = true;
        }
    }

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        /* Save previous temperature for rising detection before updating */
        controller->prev_temperature_c = controller->last_temperature_c;
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;
        is_timeout = false;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        controller->has_valid_sensor = false;
        is_timeout = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No new input - check for timeout based on elapsed time */
        if (is_timeout) {
            controller->has_valid_sensor = false;
        }
        break;
    }

    /* On timeout or invalid input, fail safe to heater off */
    if (!controller->has_valid_sensor || is_timeout) {
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_SAFE_OFF;
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
        output.timed_out = is_timeout;
        return output;
    }

    /* Apply control policy based on temperature */
    int temp = controller->last_temperature_c;

    /* Determine if temperature is rising compared to previous valid sample */
    bool rising = false;
    if (controller->prev_temperature_c > 0) {
        rising = (temp > controller->prev_temperature_c);
    }

    /* Control policy implementation: */
    if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
        /* TEMP < 47: turn heater on, enter HEATING state */
        controller->heater_on = true;
        controller->state = CONTROLLER_STATE_HEATING;
    } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* TEMP > 52: turn heater off, enter SAFE_OFF state */
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_SAFE_OFF;
    } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < 50) {
        /* 47 <= TEMP < 50: hold previous safe actuator state, enter HOLDING */
        controller->state = CONTROLLER_STATE_HOLDING;
        /* heater_on remains unchanged */
    } else if (temp >= 50 && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* 50 <= TEMP <= 52: check if rising to decide early off */
        if (rising) {
            /* Rising temperature: turn heater off early, count as HOLDING */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            /* Not rising: hold previous safe actuator state, enter HOLDING */
            controller->state = CONTROLLER_STATE_HOLDING;
            /* heater_on remains unchanged */
        }
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

